1	import { useState, useCallback, useMemo } from "react";
2	import { useQueryClient } from "@tanstack/react-query";
3	import { useStyleGroups, useStyleGroupCount, useUngroupedCount, useTotalAssetCount, type StyleGroup } from "@/hooks/useStyleGroups";
4	import { useAssets, useFilterOptions, useFilterCounts, useVisibilityDate, usePathFacets } from "@/hooks/useAssets";
5	import { defaultFilters, countActiveFilters, type AssetFilters, type SortField, type SortDirection, type ViewMode, type LibraryMode } from "@/types/assets";
6	import type { Asset } from "@/types/assets";
7	import LibraryTopBar from "@/components/library/LibraryTopBar";
8	import ScanMonitorBanner from "@/components/library/ScanMonitorBanner";
9	import FilterSidebar from "@/components/library/FilterSidebar";
10	import StyleGroupGrid from "@/components/library/StyleGroupGrid";
11	import StyleGroupListView from "@/components/library/StyleGroupListView";
12	import StyleGroupDetailPanel from "@/components/library/StyleGroupDetailPanel";
13	import AssetGrid from "@/components/library/AssetGrid";
14	import AssetListView from "@/components/library/AssetListView";
15	import AssetDetailPanel from "@/components/library/AssetDetailPanel";
16	import BulkActionBar from "@/components/library/BulkActionBar";
17	import PaginationBar from "@/components/library/PaginationBar";
18	import { useAgentStatus } from "@/hooks/useAgentStatus";
19	import { useScanProgress } from "@/hooks/useScanProgress";
20	import { useScanLifecycle } from "@/hooks/useScanLifecycle";
21	import { useSelectionManager } from "@/hooks/useSelectionManager";
22	import { Badge } from "@/components/ui/badge";
23	import { useRef } from "react";
24	
25	export default function LibraryPage() {
26	  const queryClient = useQueryClient();
27	  const [filters, setFilters] = useState<AssetFilters>(defaultFilters);
28	  const [sortField, setSortField] = useState<SortField>("modified_at");
29	  const [sortDirection, setSortDirection] = useState<SortDirection>("desc");
30	  const [viewMode, setViewMode] = useState<ViewMode>("grid");
31	  const [libraryMode, setLibraryMode] = useState<LibraryMode>("groups");
32	  const [cardStyle, setCardStyle] = useState<import("@/types/assets").CardStyle>("gallery");
33	  const [filtersOpen, setFiltersOpen] = useState(false);
34	  const [page, setPage] = useState(0);
35	  const [pageSize, setPageSize] = useState(200);
36	  const [detailGroupId, setDetailGroupId] = useState<string | null>(null);
37	  const [detailAssetId, setDetailAssetId] = useState<string | null>(null);
38	
39	  // ── Agent & scan state ──────────────────────────────────────────
40	  const agentStatus = useAgentStatus();
41	  const scanProgress = useScanProgress();
42	  const {
43	    scanTriggered, scanRunning, scanQueued,
44	    lastScanStatus, lastScanTime, lastScanSummary,
45	    handleSync, handleStopScan,
46	  } = useScanLifecycle(scanProgress);
47	
48	  // ── Data queries ────────────────────────────────────────────────
49	  const { data: visibilityDate } = useVisibilityDate();
50	  const { data: sgData, isLoading: sgLoading } = useStyleGroups(filters, sortField, sortDirection, page, pageSize, visibilityDate);
51	  const { data: totalGroupCount } = useStyleGroupCount(filters, visibilityDate);
52	  const { data: ungroupedCount } = useUngroupedCount();
53	  const { data: totalAssets } = useTotalAssetCount();
54	  const { data: assetData, isLoading: assetLoading } = useAssets(filters, sortField, sortDirection, page, visibilityDate, pageSize);
55	  const { licensors, properties } = useFilterOptions(filters.licensorId);
56	  const { data: facetCounts } = useFilterCounts(filters);
57	  const { data: pathFacets } = usePathFacets(filters.customer);
58	
59	  const isGroupsMode = libraryMode === "groups";
60	  const groups = sgData?.groups ?? [];
61	  const assets = assetData?.assets ?? [];
62	  const isLoading = isGroupsMode ? sgLoading : assetLoading;
63	  const count = isGroupsMode
64	    ? (totalGroupCount ?? sgData?.totalCount ?? 0)
65	    : (assetData?.totalCount ?? 0);
66	
67	  // ── Selection ───────────────────────────────────────────────────
68	  const currentItems = isGroupsMode ? groups : assets;
69	  const { selectedIds, setSelectedIds, handleSelect: rawHandleSelect, clearSelection } = useSelectionManager(currentItems);
70	
71	  const handleSelect = useCallback((id: string, event: React.MouseEvent) => {
72	    rawHandleSelect(id, event, (clickedId) => {
73	      if (isGroupsMode) {
74	        setDetailGroupId((prev) => (prev === clickedId ? null : clickedId));
75	        setDetailAssetId(null);
76	      } else {
77	        setDetailAssetId((prev) => (prev === clickedId ? null : clickedId));
78	        setDetailGroupId(null);
79	      }
80	    });
81	  }, [rawHandleSelect, isGroupsMode]);
82	
83	  // ── Mode switching ──────────────────────────────────────────────
84	  const handleLibraryModeChange = useCallback((mode: LibraryMode) => {
85	    setLibraryMode(mode);
86	    clearSelection();
87	    setDetailGroupId(null);
88	    setDetailAssetId(null);
89	    setPage(0);
90	  }, [clearSelection]);
91	
92	  // ── Search ──────────────────────────────────────────────────────
93	  const [searchInput, setSearchInput] = useState("");
94	  const searchTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
95	
96	  const handleSearchChange = useCallback((value: string) => {
97	    setSearchInput(value);
98	    if (searchTimerRef.current) clearTimeout(searchTimerRef.current);
99	    searchTimerRef.current = setTimeout(() => {
100	      setFilters((f) => ({ ...f, search: value }));
101	      setPage(0);
102	    }, 300);
103	  }, []);
104	
105	  const handleFiltersChange = useCallback((f: AssetFilters) => {
106	    setFilters(f);
107	    setPage(0);
108	  }, []);
109	
110	  const handleRefresh = useCallback(() => {
111	    queryClient.invalidateQueries({ queryKey: ["style-groups"] });
112	    queryClient.invalidateQueries({ queryKey: ["style-group-count"] });
113	    queryClient.invalidateQueries({ queryKey: ["filter-counts"] });
114	    queryClient.invalidateQueries({ queryKey: ["ungrouped-asset-count"] });
115	    queryClient.invalidateQueries({ queryKey: ["assets"] });
116	  }, [queryClient]);
117	
118	  const activeFilterCount = countActiveFilters(filters);
119	  const selectedGroups = groups.filter((g) => selectedIds.has(g.id));
120	
121	  const detailGroup = useMemo(
122	    () => (detailGroupId ? groups.find((g) => g.id === detailGroupId) ?? null : null),
123	    [detailGroupId, groups],
124	  );
125	
126	  const detailAsset = useMemo(
127	    () => (detailAssetId ? assets.find((a) => a.id === detailAssetId) ?? null : null),
128	    [detailAssetId, assets],
129	  );
130	
131	  return (
132	    <div className="flex h-[calc(100vh-3.5rem)] flex-col">
133	      <LibraryTopBar
134	        search={searchInput}
135	        onSearchChange={handleSearchChange}
136	        viewMode={viewMode}
137	        onViewModeChange={setViewMode}
138	        libraryMode={libraryMode}
139	        onLibraryModeChange={handleLibraryModeChange}
140	        sortField={sortField}
141	        onSortFieldChange={(f) => { setSortField(f); setPage(0); }}
142	        sortDirection={sortDirection}
143	        onSortDirectionChange={(d) => { setSortDirection(d); setPage(0); }}
144	        filtersOpen={filtersOpen}
145	        onToggleFilters={() => setFiltersOpen(!filtersOpen)}
146	        activeFilterCount={activeFilterCount}
147	        totalCount={isGroupsMode ? ((totalGroupCount ?? 0) + (ungroupedCount ?? 0)) : (assetData?.totalCount ?? 0)}
148	        totalAssets={totalAssets ?? 0}
149	        scanRunning={scanRunning}
150	        scanStale={scanProgress.status === "stale"}
151	        scanQueued={scanQueued}
152	        scanPending={scanTriggered && !scanRunning && !scanQueued}
153	        onSync={handleSync}
154	        onStopScan={handleStopScan}
155	        onRefresh={handleRefresh}
156	        scanCurrentPath={scanProgress.current_path}
157	        lastScanStatus={lastScanStatus}
158	        lastScanTime={lastScanTime}
159	        lastScanSummary={lastScanSummary}
160	        scanBlocked={agentStatus.scanBlocked}
161	        scanBlockedReason={agentStatus.scanBlockedReason}
162	        cardStyle={cardStyle}
163	        onCardStyleChange={setCardStyle}
164	        groupCount={isGroupsMode ? ((totalGroupCount ?? 0) + (ungroupedCount ?? 0)) : 0}
165	        fileCount={isGroupsMode ? (totalAssets ?? 0) : (assetData?.totalCount ?? 0)}
166	      />
167	
168	      <ScanMonitorBanner scanProgress={scanProgress} onStopScan={handleStopScan} />
169	
170	      {isGroupsMode && selectedIds.size > 0 && (
171	        <BulkActionBar
172	          selectedGroups={selectedGroups}
173	          onClearSelection={() => setSelectedIds(new Set())}
174	        />
175	      )}
176	
177	      {/* Ungrouped count indicator — groups mode only */}
178	      {isGroupsMode && ungroupedCount != null && ungroupedCount > 0 && (
179	        <div className="flex items-center gap-2 px-4 py-1.5 border-b border-border bg-muted/30 text-xs text-muted-foreground">
180	          <Badge variant="secondary" className="text-[10px]">{ungroupedCount} ungrouped</Badge>
181	          <span>assets not in any style group</span>
182	        </div>
183	      )}
184	
185	      <div className="relative flex flex-1 overflow-hidden">
186	        {filtersOpen && (
187	          <FilterSidebar
188	            filters={filters}
189	            onFiltersChange={handleFiltersChange}
190	            onClose={() => setFiltersOpen(false)}
191	            licensors={licensors}
192	            properties={properties}
193	            facetCounts={facetCounts ?? null}
194	            customerOptions={pathFacets?.customers ?? []}
195	            programOptions={pathFacets?.programs ?? []}
196	            mode={libraryMode === "assets" ? "assets" : "groups"}
197	          />
198	        )}
199	
200	        <div className="flex flex-1 flex-col overflow-auto">
201	          {isGroupsMode ? (
202	            viewMode === "grid" ? (
203	              <StyleGroupGrid
204	                groups={groups}
205	                selectedIds={selectedIds}
206	                onSelect={handleSelect}
207	                isLoading={isLoading}
208	                rebuildHint={groups.length === 0 && ((totalGroupCount ?? 0) > 0 || (ungroupedCount ?? 0) > 0)}
209	              />
210	            ) : (
211	              <StyleGroupListView
212	                groups={groups}
213	                selectedIds={selectedIds}
214	                onSelect={handleSelect}
215	                isLoading={isLoading}
216	                rebuildHint={groups.length === 0 && ((totalGroupCount ?? 0) > 0 || (ungroupedCount ?? 0) > 0)}
217	              />
218	            )
219	          ) : (
220	            viewMode === "grid" ? (
221	              <AssetGrid
222	                assets={assets}
223	                selectedIds={selectedIds}
224	                onSelect={handleSelect}
225	                onOpenDetail={setDetailAssetId}
226	                isLoading={isLoading}
227	              />
228	            ) : (
229	              <AssetListView
230	                assets={assets}
231	                selectedIds={selectedIds}
232	                onSelect={handleSelect}
233	                isLoading={isLoading}
234	              />
235	            )
236	          )}
237	
238	          <div className="mt-auto">
239	            <PaginationBar
240	              page={page}
241	              totalCount={count}
242	              pageSize={pageSize}
243	              onPageChange={setPage}
244	              onPageSizeChange={(size) => { setPageSize(size); setPage(0); }}
245	            />
246	          </div>
247	        </div>
248	
249	        {/* Detail panel: style group */}
250	        {isGroupsMode && detailGroup && (
251	          <div className="h-full max-[1399px]:absolute max-[1399px]:inset-y-0 max-[1399px]:right-0 max-[1399px]:z-20 max-[1399px]:shadow-xl">
252	            <StyleGroupDetailPanel
253	              key={detailGroup.id}
254	              group={detailGroup}
255	              onClose={() => setDetailGroupId(null)}
256	            />
257	          </div>
258	        )}
259	
260	        {/* Detail panel: individual asset */}
261	        {!isGroupsMode && detailAsset && (
262	          <div className="h-full max-[1399px]:absolute max-[1399px]:inset-y-0 max-[1399px]:right-0 max-[1399px]:z-20 max-[1399px]:shadow-xl">
263	            <AssetDetailPanel
264	              asset={detailAsset}
265	              onClose={() => setDetailAssetId(null)}
266	            />
267	          </div>
268	        )}
269	      </div>
270	    </div>
271	  );
272	}
